CREATE TABLE `biz_work_order` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `work_order_no` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '工单编号，全局唯一',
  `order_type` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '工单类型: 产品申购/产品赎回/信息变更/投诉建议/风评重做/可疑交易上报',
  `sub_type` varchar(32) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '子类型',
  `customer_id` bigint NOT NULL COMMENT '关联客户ID',
  `submitter_id` bigint NOT NULL COMMENT '提交人ID',
  `handler_id` bigint DEFAULT NULL COMMENT '当前处理人ID',
  `current_node` varchar(32) COLLATE utf8mb4_unicode_ci DEFAULT '初审' COMMENT '当前流程节点: 初审/复核/完成',
  `priority` varchar(8) COLLATE utf8mb4_unicode_ci DEFAULT '普通' COMMENT '优先级: 普通/紧急/特急',
  `status` varchar(16) COLLATE utf8mb4_unicode_ci DEFAULT '待处理' COMMENT '状态: 待处理/处理中/待审核/已完成/已驳回',
  `biz_content` json DEFAULT NULL COMMENT '业务内容JSON',
  `remark` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '备注',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_work_order_no` (`work_order_no`),
  KEY `idx_order_type` (`order_type`),
  KEY `idx_customer_id` (`customer_id`),
  KEY `idx_handler_id` (`handler_id`),
  KEY `idx_status` (`status`),
  KEY `idx_priority` (`priority`)
) ENGINE=InnoDB AUTO_INCREMENT=31 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='通用业务工单表';
