DROP TABLE IF EXISTS `customer_tag`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `customer_tag` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `customer_id` bigint NOT NULL COMMENT '客户ID',
  `tag_name` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '标签名（如 risk_preference）',
  `tag_value` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '标签值（如 稳健型）',
  `source` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '来源：questionnaire/ai_extract/self_report/default',
  `confidence` decimal(5,2) DEFAULT '0.50' COMMENT '标签置信度 0.00-1.00',
  `valid_until` date DEFAULT NULL COMMENT '有效期',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_customer_tag` (`customer_id`,`tag_name`),
  KEY `idx_customer_id` (`customer_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='画像标签表';
/*!40101 SET character_set_client = @saved_cs_client */;

