  `calibrate_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '校准执行时间',
  `direction` varchar(32) NOT NULL COMMENT 'over_optimistic / over_conservative / aligned',
  `self_reported` json DEFAULT NULL COMMENT '自评画像快照',
  `behavioral` json DEFAULT NULL COMMENT '行为推断画像',
