  `summary` text COMMENT '面向投顾的可读校准摘要',
  `trigger_type` varchar(32) DEFAULT 'manual' COMMENT 'manual / auto / event',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_calibration_customer` (`customer_id`),
  KEY `idx_calibration_time` (`customer_id`,`calibrate_time` DESC),
  KEY `idx_calibration_direction` (`direction`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='双轨校准历史记录';
