--
-- Table structure for table `fin_customer_profile`
--

DROP TABLE IF EXISTS `fin_customer_profile`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fin_customer_profile` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `customer_id` bigint NOT NULL COMMENT '客户ID，关联sys_user.id',
  `risk_level` varchar(16) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '风险等级: 保守型/稳健型/平衡型/进取型/激进型',
  `risk_score` int DEFAULT NULL COMMENT '风险评分0-100',
  `investment_experience` varchar(16) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '投资经验年限: 0-1年/1-3年/3-5年/5-10年/10年以上',
  `annual_income_range` varchar(32) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '年收入区间',
  `total_assets` decimal(18,2) DEFAULT NULL COMMENT '总资产规模(人民币元)',
  `asset_allocation` json DEFAULT NULL COMMENT '资产配置偏好',
  `product_preference` json DEFAULT NULL COMMENT '产品偏好',
  `confidence_score` decimal(5,2) DEFAULT '0.50' COMMENT '画像置信度0.00-1.00',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `basic_score` decimal(5,2) DEFAULT NULL COMMENT '维度一：基础属性得分',
  `experience_score` decimal(5,2) DEFAULT NULL COMMENT '维度二：投资经验得分',
  `risk_pref_score` decimal(5,2) DEFAULT NULL COMMENT '维度三：风险偏好得分',
  `behavior_score` decimal(5,2) DEFAULT NULL COMMENT '维度四：行为异常得分',
  `profile_json` json DEFAULT NULL COMMENT '完整画像JSON',
  `risk_flag` varchar(16) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '风险标记: normal/warning/high',
  `calibration_json` json DEFAULT NULL COMMENT 'Latest dual-track calibration result snapshot',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_customer_id` (`customer_id`),
  KEY `idx_risk_level` (`risk_level`),
  KEY `idx_total_assets` (`total_assets`)
) ENGINE=InnoDB AUTO_INCREMENT=44 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='客户画像主表';
/*!40101 SET character_set_client = @saved_cs_client */;

