--
-- Table structure for table `fin_risk_alert`
--

DROP TABLE IF EXISTS `fin_risk_alert`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fin_risk_alert` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `customer_id` bigint NOT NULL COMMENT '被预警客户ID',
  `alert_type` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '预警类型: 大额交易/频繁交易/关联交易/异常登录/疑似洗钱',
  `alert_level` varchar(8) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '预警级别: 低(蓝)/中(黄)/高(红)',
  `trigger_detail` text COLLATE utf8mb4_unicode_ci COMMENT '触发详情',
  `transaction_ids` json DEFAULT NULL COMMENT '关联交易ID列表',
  `status` varchar(16) COLLATE utf8mb4_unicode_ci DEFAULT '未处理' COMMENT '状态: 未处理/处理中/已确认/已排除',
  `handler_id` bigint DEFAULT NULL COMMENT '处理人(风控专员)ID',
  `handle_result` text COLLATE utf8mb4_unicode_ci COMMENT '处理结果结论文本',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_customer_id` (`customer_id`),
  KEY `idx_alert_level` (`alert_level`),
  KEY `idx_status` (`status`),
  KEY `idx_create_time` (`create_time`)
) ENGINE=InnoDB AUTO_INCREMENT=37 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='风控预警表';
/*!40101 SET character_set_client = @saved_cs_client */;

