--
-- Table structure for table `fin_transaction`
--

DROP TABLE IF EXISTS `fin_transaction`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fin_transaction` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `transaction_no` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '交易流水号，全局唯一',
  `customer_id` bigint NOT NULL COMMENT '交易客户ID',
  `product_id` bigint NOT NULL COMMENT '交易产品ID',
  `transaction_type` varchar(16) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '交易类型: 申购/赎回/转账/分红/定投',
  `amount` decimal(18,2) DEFAULT NULL COMMENT '交易金额(元)',
  `shares` decimal(18,4) DEFAULT NULL COMMENT '成交份额',
  `nav` decimal(12,6) DEFAULT NULL COMMENT '成交净值',
  `fee` decimal(12,2) DEFAULT '0.00' COMMENT '手续费(元)',
  `status` varchar(16) COLLATE utf8mb4_unicode_ci DEFAULT '待确认' COMMENT '状态: 待确认/已确认/已撤单/失败',
  `operator_id` bigint DEFAULT NULL COMMENT '经办理财顾问ID',
  `remark` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '备注',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_transaction_no` (`transaction_no`),
  KEY `idx_customer_id` (`customer_id`),
  KEY `idx_product_id` (`product_id`),
  KEY `idx_transaction_type` (`transaction_type`),
  KEY `idx_status` (`status`),
  KEY `idx_create_time` (`create_time`)
) ENGINE=InnoDB AUTO_INCREMENT=126 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='交易流水表';
/*!40101 SET character_set_client = @saved_cs_client */;

