DROP TABLE IF EXISTS `product_recommendation`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `product_recommendation` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '推荐ID',
  `customer_id` bigint NOT NULL COMMENT '客户ID',
  `session_id` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '会话ID',
  `product_code` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '推荐产品代码',
  `match_score` decimal(5,2) DEFAULT NULL COMMENT '匹配评分',
  `score_detail` json DEFAULT NULL COMMENT '评分明细',
  `reasoning` text COLLATE utf8mb4_unicode_ci COMMENT '推荐理由',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '推荐时间',
  PRIMARY KEY (`id`),
  KEY `idx_customer_id` (`customer_id`),
  KEY `idx_session_id` (`session_id`)
) ENGINE=InnoDB AUTO_INCREMENT=34 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='推荐结果表';
/*!40101 SET character_set_client = @saved_cs_client */;

