--
-- Table structure for table `risk_rule`
--

DROP TABLE IF EXISTS `risk_rule`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `risk_rule` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `rule_id` varchar(16) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '规则编号（如 FM-01）',
  `rule_name` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '规则名称',
  `rule_type` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '类型：scoring/circuit_breaker',
  `dimension` varchar(32) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '所属维度',
  `config_json` json DEFAULT NULL COMMENT '规则配置（分值表、阈值等）',
  `weight` decimal(5,2) DEFAULT NULL COMMENT '权重',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '是否启用',
  `version` varchar(16) COLLATE utf8mb4_unicode_ci DEFAULT '1.0' COMMENT '版本号',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_rule_id` (`rule_id`)
) ENGINE=InnoDB AUTO_INCREMENT=31 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='规则配置表';
