INSERT INTO `risk_rule` VALUES (1,'D1-AGE','年龄评分','scoring','basic','{\"65+\": 3, \"18-25\": 8, \"26-35\": 10, \"36-45\": 9, \"46-55\": 7, \"56-65\": 5}',0.20,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(2,'D1-EDU','学历评分','scoring','basic','{\"大专\": 6, \"本科\": 8, \"硕士及以上\": 10, \"高中及以下\": 4}',0.20,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(3,'D1-OCC','职业评分','scoring','basic','{\"退休\": 4, \"个体工商户\": 5, \"无固定职业\": 2, \"自由职业者\": 5, \"专业技术人员\": 8, \"中小企业员工\": 6, \"公务员/事业单位\": 10, \"大型国企/上市公司正式员工\": 9}',0.20,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(4,'D1-INC','收入评分','scoring','basic','{\"<10万\": 3, \">300万\": 10, \"10-30万\": 5, \"30-50万\": 7, \"50-100万\": 8, \"100-300万\": 9}',0.20,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(5,'D1-AST','资产评分','scoring','basic','{\"<5万\": 2, \"5-20万\": 4, \"20-50万\": 6, \">1000万\": 10, \"50-100万\": 7, \"100-500万\": 8, \"500-1000万\": 9}',0.20,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(6,'D2-YEARS','投资年限评分','scoring','experience','{\"<1年\": 4, \"1-3年\": 6, \"3-5年\": 8, \">10年\": 10, \"5-10年\": 9, \"无投资经验\": 2}',0.25,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(7,'D2-COMPLEX','产品复杂度评分','scoring','experience','{\"仅银行存款\": 2, \"货币基金/国债\": 4, \"股票/股票基金/ETF(R4)\": 8, \"混合基金/指数基金(R3)\": 7, \"纯债基金/银行理财(R1-R2)\": 5, \"期货/期权/私募/结构化产品(R5)\": 10}',0.25,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(8,'D2-FREQ','交易频率评分','scoring','experience','{\"中频\": 8, \"低频\": 7, \"高频\": 6, \"极低频\": 5}',0.25,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(9,'D2-RETURN','历史收益评分','scoring','experience','{\">15%\": 9, \"<-15%\": 3, \"-5%~5%\": 6, \"5%~15%\": 8, \"-15%~-5%\": 4, \"无历史记录\": 3}',0.25,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(10,'D3-MAP','风评等级映射','scoring','risk_pref','{\"C1\": 5, \"C2\": 10, \"C3\": 15, \"C4\": 20, \"C5\": 25}',0.33,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(11,'D3-EMOTION','情绪化交易扣分','scoring','risk_pref','[{\"penalty\": -3, \"behavior\": \"追涨杀跌\", \"description\": \"净值新高后3日内买入/新低后3日内卖出\"}, {\"penalty\": -5, \"behavior\": \"恐慌赎回\", \"description\": \"市场大跌(>5%)当日赎回超持仓50%\"}, {\"penalty\": -2, \"behavior\": \"FOMO加仓\", \"description\": \"连续3日上涨后大额加仓超月均3倍\"}, {\"penalty\": -3, \"behavior\": \"频繁改策略\", \"description\": \"90天内调整投资组合配置超过3次\"}]',0.33,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(12,'D3-LOSS','亏损承受调整','scoring','risk_pref','{\"10%-20%\": 0, \"20%-40%\": 3, \"5%以内\": -2, \"40%以上\": 5, \"不能承受任何亏损\": -5}',0.33,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(13,'D4-BEHAVIOR','异常行为规则','scoring','behavior','[{\"id\": \"B001\", \"name\": \"频繁赎回\", \"risk\": \"中\", \"rule\": \"30天内赎回次数≥5次\"}, {\"id\": \"B002\", \"name\": \"大额集中交易\", \"risk\": \"中\", \"rule\": \"单日交易金额超过账户总资产50%\"}, {\"id\": \"B003\", \"name\": \"非正常时段交易\", \"risk\": \"低\", \"rule\": \"凌晨0:00-6:00频繁登录/交易\"}, {\"id\": \"B004\", \"name\": \"突然大额入金\", \"risk\": \"中\", \"rule\": \"单笔入金超过历史平均5倍以上\"}, {\"id\": \"B005\", \"name\": \"分散转出\", \"risk\": \"高\", \"rule\": \"单日出金至5个以上不同银行账户\"}, {\"id\": \"B006\", \"name\": \"产品风险越级\", \"risk\": \"高\", \"rule\": \"要求购买超过风险等级2级以上的产品\"}, {\"id\": \"B007\", \"name\": \"信息频繁变更\", \"risk\": \"中\", \"rule\": \"30天内变更手机/地址≥3次\"}, {\"id\": \"B008\", \"name\": \"代理操作\", \"risk\": \"高\", \"rule\": \"频繁由同一非本人设备/IP操作\"}]',0.50,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(14,'D4-SCORE','异常行为得分','scoring','behavior','{\"无异常\": 20, \"1-2项中风险\": 10, \"1-2项低风险\": 15, \"任何高风险\": 0, \"3项以上中风险\": 5}',0.50,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(15,'LEVEL-MAP','等级映射','scoring',NULL,'[[0, 25, \"C1\", \"保守型\"], [26, 40, \"C2\", \"稳健型\"], [41, 60, \"C3\", \"平衡型\"], [61, 80, \"C4\", \"进取型\"], [81, 100, \"C5\", \"激进型\"]]',NULL,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(16,'SUIT-MATRIX','适当性矩阵','scoring',NULL,'{\"C1\": [\"R1\", \"R2\"], \"C2\": [\"R1\", \"R2\", \"R3\"], \"C3\": [\"R1\", \"R2\", \"R3\", \"R4\"], \"C4\": [\"R1\", \"R2\", \"R3\", \"R4\", \"R5\"], \"C5\": [\"R1\", \"R2\", \"R3\", \"R4\", \"R5\"]}',NULL,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(17,'DIM-WEIGHT','维度权重','scoring',NULL,'{\"basic\": 0.25, \"behavior\": 0.2, \"risk_pref\": 0.3, \"experience\": 0.25}',NULL,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(18,'CONFIDENCE-SRC','置信度初始权重','scoring',NULL,'{\"default\": 0.2, \"behavior\": 0.8, \"ai_extract\": 0.6, \"self_report\": 0.4, \"questionnaire\": 0.9}',NULL,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(19,'RECOMMEND-WEIGHT','推荐引擎权重','scoring',NULL,'{\"preference\": 0.2, \"risk_match\": 0.35, \"return_term\": 0.15, \"graph_signal\": 0.15, \"diversification\": 0.15}',NULL,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(20,'ASSET-ALLOC','资产配置模板','scoring',NULL,'{\"C1\": {\"现金\": 0.2, \"债券类\": 0.4, \"混合类\": 0, \"股票类\": 0, \"货币类\": 0.4}, \"C2\": {\"现金\": 0.1, \"债券类\": 0.5, \"混合类\": 0.2, \"股票类\": 0, \"货币类\": 0.2}, \"C3\": {\"现金\": 0.05, \"债券类\": 0.35, \"混合类\": 0.3, \"股票类\": 0.2, \"货币类\": 0.1}, \"C4\": {\"现金\": 0.05, \"债券类\": 0.2, \"混合类\": 0.3, \"股票类\": 0.4, \"货币类\": 0.05}, \"C5\": {\"现金\": 0.1, \"债券类\": 0.1, \"混合类\": 0.25, \"股票类\": 0.55, \"货币类\": 0}}',NULL,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(21,'FM-01','年龄限制','circuit_breaker',NULL,'{\"rule_id\": \"FM-01\", \"rule_name\": \"年龄限制\", \"conditions\": [{\"cond\": \"age < 18\", \"level\": \"block\", \"action\": \"禁止开户\"}, {\"cond\": \"18 <= age <= 22\", \"level\": \"restrict\", \"action\": \"R4+需监护人知情同意书\"}, {\"cond\": \"age > 70\", \"level\": \"restrict\", \"action\": \"R3+需网点面签确认\"}, {\"cond\": \"age > 80\", \"level\": \"restrict\", \"action\": \"仅允许R1-R2，R3需特殊审批\"}]}',NULL,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(22,'FM-02','收入与资产限制','circuit_breaker',NULL,'{\"rule_id\": \"FM-02\", \"rule_name\": \"收入与资产限制\", \"conditions\": [{\"cond\": \"no_income AND assets < 10000\", \"level\": \"restrict\", \"action\": \"仅允许R1-R2\"}, {\"cond\": \"no_income AND 10000 <= assets <= 50000\", \"level\": \"restrict\", \"action\": \"R1-R3，R3持仓不超过总资产30%\"}]}',NULL,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(23,'FM-03','风评时效检查','circuit_breaker',NULL,'{\"rule_id\": \"FM-03\", \"rule_name\": \"风评时效检查\", \"conditions\": [{\"cond\": \"days_since_risk > 365\", \"level\": \"block\", \"action\": \"冻结购买权限，仅允许赎回\"}, {\"cond\": \"days_since_risk > 180\", \"level\": \"warn\", \"action\": \"发送提醒通知\"}]}',NULL,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(24,'FM-04','身份异常检查','circuit_breaker',NULL,'{\"rule_id\": \"FM-04\", \"rule_name\": \"身份异常检查\", \"conditions\": [{\"cond\": \"id_expired_days > 90\", \"level\": \"block\", \"action\": \"冻结账户全部交易权限\"}, {\"cond\": \"identity_check_failed\", \"level\": \"restrict\", \"action\": \"暂停非柜面交易\"}, {\"cond\": \"sanction_list_match\", \"level\": \"block\", \"action\": \"立即冻结，上报合规\"}]}',NULL,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(25,'FM-05','异常交易熔断','circuit_breaker',NULL,'{\"rule_id\": \"FM-05\", \"rule_name\": \"异常交易熔断\", \"conditions\": [{\"cond\": \"daily_loss > total_assets * 0.1\", \"level\": \"warn\", \"action\": \"推送风险提示\"}, {\"cond\": \"consecutive_redeem > total_assets * 0.4\", \"level\": \"restrict\", \"action\": \"触发人工回访\"}, {\"cond\": \"account_theft_suspected\", \"level\": \"block\", \"action\": \"立即冻结账户\"}]}',NULL,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(26,'SP-STUDENT','在校学生','special',NULL,'{\"note\": \"无独立收入\", \"product_limit\": [\"R1\", \"R2\"], \"income_treatment\": 0}',NULL,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(27,'SP-DISHONEST','失信被执行人','special',NULL,'{\"action\": \"限制大额申购，加强资金来源核实\"}',NULL,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(28,'SP-FOREIGN','外籍人士','special',NULL,'{\"action\": \"增加国籍/地区风险因子，高风险国家下调一档\"}',NULL,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(29,'SP-CONFLICT','自评vs AI冲突','special',NULL,'{\"diff_1\": \"取AI评估结果，允许客户申请人工复核\", \"diff_2\": \"取AI评估结果，客户需到网点进行面对面评估\", \"diff_3+\": \"取AI评估结果，触发合规调查\"}',NULL,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22'),(30,'SP-INCOMPLETE','信息不完整规则','special',NULL,'{\"收入缺失\": \"按当地最低工资标准估算，风险评级下调一档\", \"资产缺失\": \"仅依据已知金融资产评估\", \"投资经验缺失\": \"投资经验维度默认3分（保守处理）\", \"联系方式失效\": \"限制非柜面交易\", \"多项缺失(≥3项)\": \"暂停新开户，需人工审核\"}',NULL,1,'1.0','2026-07-23 22:00:22','2026-07-23 22:00:22');
