DROP TABLE IF EXISTS `risk_score_record`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `risk_score_record` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '记录ID',
  `customer_id` bigint NOT NULL COMMENT '客户ID',
  `rating_date` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '评分日期',
  `basic_score` decimal(5,2) DEFAULT NULL COMMENT '基础属性评分',
  `experience_score` decimal(5,2) DEFAULT NULL COMMENT '投资经验评分',
  `risk_pref_score` decimal(5,2) DEFAULT NULL COMMENT '风险偏好评分',
  `behavior_score` decimal(5,2) DEFAULT NULL COMMENT '行为异常评分',
  `total_score` decimal(5,2) DEFAULT NULL COMMENT '综合评分',
  `risk_level` varchar(16) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '评定等级 C1-C5',
  `detail_json` json DEFAULT NULL COMMENT '各子项评分明细',
  `circuit_breakers` json DEFAULT NULL COMMENT '触发的熔断规则',
  `trigger_type` varchar(32) COLLATE utf8mb4_unicode_ci DEFAULT 'manual' COMMENT '触发方式：manual/auto/event',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_customer_id` (`customer_id`),
  KEY `idx_rating_date` (`rating_date`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='评分过程记录表';
