--
-- Table structure for table `sys_user`
--

DROP TABLE IF EXISTS `sys_user`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `sys_user` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '全局唯一用户标识',
  `username` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '登录账号',
  `password_hash` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'BCrypt/Argon2加密密码',
  `user_type` varchar(16) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '用户类型: CUSTOMER=客户, EMPLOYEE=员工',
  `employee_role` varchar(32) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '员工角色: 理财顾问/风控专员/客户经理/管理员',
  `customer_level` varchar(16) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '客户等级: 普通/金卡/白金/钻石/私行',
  `real_name` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '真实姓名',
  `phone` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '手机号',
  `id_card` varchar(18) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '身份证号',
  `email` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '邮箱',
  `status` varchar(16) COLLATE utf8mb4_unicode_ci DEFAULT '正常' COMMENT '账号状态: 正常/禁用/冻结',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `education` varchar(32) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '学历',
  `occupation` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '职业',
  `age` int DEFAULT NULL COMMENT '年龄',
  `id_card_expiry` date DEFAULT NULL COMMENT '身份证有效期',
  `balance` decimal(18,2) NOT NULL DEFAULT '0.00',
  `role` varchar(32) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '角色（兼容旧版代码）',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_username` (`username`),
  KEY `idx_user_type` (`user_type`),
  KEY `idx_status` (`status`),
  KEY `idx_customer_level` (`customer_level`),
  KEY `idx_employee_role` (`employee_role`)
) ENGINE=InnoDB AUTO_INCREMENT=56 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='统一用户表';
/*!40101 SET character_set_client = @saved_cs_client */;

