INSERT INTO `table_name` VALUES (1,'sys_user','统一用户表','客户与员工共用一套账号体系，通过user_type字段区分','用户',1,'2026-07-22 10:19:57'),(2,'fin_customer_profile','客户画像主表','承载风险评测结果、资产概况、投资偏好，是投顾推荐的核心上下文','用户',2,'2026-07-22 10:19:57'),(3,'fin_product','理财产品表','理财产品目录，覆盖基金、银行理财、保险、信托等全品类','产品',3,'2026-07-22 10:19:57'),(4,'fin_transaction','交易流水表','记录客户所有交易动作（申购/赎回/转账/分红/定投）','交易',4,'2026-07-22 10:19:57'),(5,'fin_holdings','持仓表','客户当前/历史持仓快照','交易',5,'2026-07-22 10:19:57'),(6,'fin_risk_assessment','风险评估记录表','每次风评独立存档，用于审计追溯和画像置信度计算','风控',6,'2026-07-22 10:19:57'),(7,'fin_risk_alert','风控预警表','AI/规则引擎产出的预警事件，供风控专员处置','风控',7,'2026-07-22 10:19:57'),(8,'biz_work_order','通用业务工单表','统一承载所有业务流程（申购/赎回/信息变更/投诉等）','工单',8,'2026-07-22 10:19:57'),(9,'conversation_archive','会话归档表','所有Agent的对话按轮次落库，用于审计和回溯','知识库',9,'2026-07-22 10:19:57'),(10,'fin_knowledge_meta','金融知识元数据表','RAG知识库的\"书目录\"，记录文档元数据','知识库',10,'2026-07-22 10:19:57');
